def _reorder_palette(self, mode, palette_data, num_colors, sort_palette):
    """
    Reorders the first ``num_colors`` entries of a "P" image's palette
    (and remaps its pixel data to match) according to ``sort_palette``.
    Entries beyond ``num_colors`` are unused padding and are left alone.
    Used by :py:meth:`~PIL.Image.Image.quantize`.
    """
    if callable(sort_palette):
        key = sort_palette
    elif sort_palette == "luminance":

        def key(color):
            r, g, b = color[0], color[1], color[2]
            return r * 299 + g * 587 + b * 114

    elif sort_palette == "rgb":

        def key(color):
            return color

    else:
        raise ValueError(
            "sort_palette must be 'luminance', 'rgb', a callable, or None"
        )

    channels = len(mode)
    colors = [
        tuple(palette_data[i : i + channels])
        for i in range(0, num_colors * channels, channels)
    ]

    # indices into the old palette, in the desired new order
    new_order = sorted(range(len(colors)), key=lambda i: key(colors[i]))

    new_palette_data = (
        b"".join(bytes(colors[i]) for i in new_order)
        + palette_data[num_colors * channels :]
    )

    # build a lookup table mapping each old palette index to its new one
    index_map = list(range(256))
    for new_index, old_index in enumerate(new_order):
        index_map[old_index] = new_index

    im = self.point(index_map)
    im.im.putpalette(mode, new_palette_data)

    return new_palette_data, im

